#include <bits/stdc++.h>
using namespace std;

bool solve(vector<int>& nums) {
    int goal = nums.size() - 1;

    // Start from second last position
    for(int i = nums.size() - 2; i >= 0; i--) {
        // If we can reach the goal from current position,
        // make current position the new goal
        if(i + nums[i] >= goal) {
            goal = i;
        }
    }

    // If goal becomes 0, we can reach the end
    return goal == 0;
}

int main() {
    int n;
    cin >> n;

    vector<int> nums(n);
    for(int i = 0; i < n; i++) {
        cin >> nums[i];
    }

    cout << (solve(nums) ? "YES" : "NO") << endl;
    return 0;
}

