import java.util.Scanner;

public class Main {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        if (!scanner.hasNextInt()) return;

        int n = scanner.nextInt();
        int[] a = new int[n];
        for (int i = 0; i < n; i++) {
            a[i] = scanner.nextInt();
        }

        int maxReachable = 0;
        boolean possible = true;

        for (int i = 0; i < n; i++) {
            // If the current index is beyond our maximum reachable distance, we're stuck
            if (i > maxReachable) {
                possible = false;
                break;
            }

            // Update the furthest index we can reach
            maxReachable = Math.max(maxReachable, i + a[i]);

            // If we can already reach the end, no need to check further
            if (maxReachable >= n - 1) {
                break;
            }
        }

        if (possible) {
            System.out.println("YES");
        } else {
            System.out.println("NO");
        }

        scanner.close();
    }
}

